import { api } from './api';
import type { ApiResponse } from './api';
import type { Session, CreativeBrief } from '../types/session.types';

export interface CreateSessionInput {
  coreIdea: string;
  genre: string;
  targetAudience?: string;
  themes?: string[];
}

export const sessionService = {
  create: async (brief: CreateSessionInput): Promise<Session> => {
    const response = await api.post<ApiResponse<Session>>('/sessions', brief);
    return response.data.data!;
  },

  getById: async (id: string): Promise<Session> => {
    const response = await api.get<ApiResponse<Session>>(`/sessions/${id}`);
    return response.data.data!;
  },

  list: async (): Promise<Session[]> => {
    const response = await api.get<ApiResponse<Session[]>>('/sessions');
    return response.data.data || [];
  },

  getAll: async (): Promise<Session[]> => {
    const response = await api.get<ApiResponse<Session[]>>('/sessions');
    return response.data.data || [];
  },

  delete: async (id: string): Promise<void> => {
    await api.delete(`/sessions/${id}`);
  },

  updateStatus: async (id: string, status: string): Promise<Session> => {
    const response = await api.patch<ApiResponse<Session>>(`/sessions/${id}/status`, { status });
    return response.data.data!;
  },

  update: async (id: string, data: Partial<Session>): Promise<Session> => {
    const response = await api.patch<ApiResponse<Session>>(`/sessions/${id}`, data);
    return response.data.data!;
  },

  start: async (id: string): Promise<Session> => {
    const response = await api.post<ApiResponse<Session>>(`/sessions/${id}/start`);
    return response.data.data!;
  },

  pause: async (id: string): Promise<Session> => {
    const response = await api.post<ApiResponse<Session>>(`/sessions/${id}/pause`);
    return response.data.data!;
  },

  resume: async (id: string): Promise<Session> => {
    const response = await api.post<ApiResponse<Session>>(`/sessions/${id}/resume`);
    return response.data.data!;
  }
};
